private boolean backtrack(String pattern, int pi, String s, int si,
                           Map<Character, String> charToWord, Set<String> used) {
    if (pi == pattern.length() && si == s.length()) return true;
    if (pi == pattern.length() || si == s.length()) return false;

    char c = pattern.charAt(pi);

    if (charToWord.containsKey(c)) {
        String word = charToWord.get(c);
        if (!s.startsWith(word, si)) return false;
        return backtrack(pattern, pi + 1, s, si + word.length(), charToWord, used);
    }

    for (int end = si + 1; end <= s.length(); end++) {
        String word = s.substring(si, end);
        if (used.contains(word)) continue;
        charToWord.put(c, word);
        used.add(word);
        if (backtrack(pattern, pi + 1, s, end, charToWord, used)) return true;
        charToWord.remove(c);
        used.remove(word);
    }

    return false;
}

