def word_pattern_match(pattern: str, s: str) -> bool:
    def backtrack(pi, si, char_to_word, used):
        if pi == len(pattern) and si == len(s):
            return True
        if pi == len(pattern) or si == len(s):
            return False

        c = pattern[pi]
        if c in char_to_word:
            word = char_to_word[c]
            if not s.startswith(word, si):
                return False
            return backtrack(pi + 1, si + len(word), char_to_word, used)

        for end in range(si + 1, len(s) + 1):
            word = s[si:end]
            if word in used:
                continue
            char_to_word[c] = word
            used.add(word)
            if backtrack(pi + 1, end, char_to_word, used):
                return True
            del char_to_word[c]
            used.remove(word)

        return False

    return backtrack(0, 0, {}, set())
